('VPI_2023_consolidated_debt_14', 'VPI', 2023, 'consolidated', 'Công ty TNHH Chứng khoán Ngân hàng TMCP Ngoại thương Việt Nam', 'long_term', 178446373178.0, '10.3%', '15.125.000 cổ phiếu phổ thông của Công ty được nắm giữ bởi bên thứ ba', '04/2024'),
('VPI_2023_consolidated_debt_15', 'VPI', 2023, 'consolidated', 'VIAC (No.1) Limited Partnership', 'long_term', 731140249737.0, '5%/năm (lãi suất gộp)', '27.225.000 cổ phiếu phổ thông của Công ty thuộc sở hữu của bên thứ ba', '11/2024'),
('VPI_2023_parent_debt_0', 'VPI', 2023, 'parent', 'Ngân hàng TNHH Indovina – Chi nhánh Thiên Long', 'short_term', 135323858207.0, '9.15%/năm', 'Tài sản đảm bảo bao gồm: Một số tài sản gắn liền với đất tại Khu dịch vụ thương mại tầng 5-CT9, Khu đô thị mới Văn Phú, phường Phúc La, quận Hà Đông, thành phố Hà Nội thuộc sở hữu của bên thứ ba; Tài sản gắn liền với đất tại Sản thương mại tầng 1, tòa nhà Home City, tổ 51, phố Trung Kính, phường Yên Hòa, quận Cầu Giấy, thành phố Hà Nội thuộc sở hữu của bên thứ ba; Quyền sở hữu 3.250.000 cổ phiếu phổ thông của Công ty thuộc sở hữu của bên thứ ba.', '12/2024'),
('VPI_2023_parent_debt_1', 'VPI', 2023, 'parent', 'Công ty Cổ phần Tư vấn Đầu tư Xây dựng Bắc Ái', 'short_term', 28900000000.0, '9.3%/năm', 'Tín chấp', '12/2024'),
('VPI_2023_parent_debt_2', 'VPI', 2023, 'parent', 'Ngân hàng TMCP Việt Nam Thịnh Vượng - Hội sở chính', 'long_term', 770419543703.0, '12.5% - 13.2%/năm', 'Toàn bộ các quyền sử dụng đất, quyền tài sản thuộc Công ty liên quan đến Dự án Đầu tư xây dựng nhà ở, nhà ở kết hợp thương mại hỗn hợp tại Phân khu số 2, Khu đồ thị phía Nam, thành phố Bắc Giang tại phường Dĩnh Kế, thành phố Bắc Giang, tỉnh Bắc Giang.', '03/2025'),
('VPI_2023_parent_debt_3', 'VPI', 2023, 'parent', 'Ngân hàng TMCP Quân Đội - Chi nhánh Điện Biên Phú', 'long_term', 348250334875.0, '9.7% - 11.9%/năm', 'Tài sản đảm bảo bao gồm: Tài sản gắn liền với đất là bất động sản tại phố Nguyễn Chí Thanh, phường Láng Thương, quận Đống Đa, thành phố Hà Nội thuộc sở hữu của bên thứ ba; Quyền sử dụng đất và nhà ở hình thành trên đất tại Iô G2-B6 thuộc Dự án Khu đồ hỗn hợp và nhà ở tại số 138B Giảng Võ, phường Kim Mã, quận Ba Đình, Hà Nội thuộc sở hữu của bên thứ ba; Quyền sở hữu tài sản gắn liền với đất là Khu dịch vụ thương mại tầng 1-01, tầng 1-02, tầng 1-03, tầng 1-04, tầng 5-01, tại tỏa CT9 thuộc Khu đô thị mới Văn Phú, phường Phúc La, quận Hà Đông, thành phố Hà Nội thuộc sở hữu của bên thứ ba; Quyền tài sản của Công ty phát sinh từ hợp đồng cho thuê tòa 1 và khoản thu tòa 2 dự án Khu dịch vụ căn hộ khách sạn Hồ Tây; Quyền sở hữu 6.400.000 cổ phiếu phổ thông của Công ty được nằm giữ bởi bên thứ ba; Toàn bộ động sản hình thành từ Dự án Khu dịch vụ căn hộ khách sạn Hồ Tây.', '04/2036'),
('VPI_2023_parent_debt_4', 'VPI', 2023, 'parent', 'Ngân hàng TMCP Việt Nam Thịnh Vượng - Hội sở chính', 'long_term', 122677000000.0, '13.2%/năm', 'Tài sản đảm bảo bao gồm: Quyền tài sản phát sinh từ Dự án đầu tư xây dựng nhà ở hỗn hợp và khu thương mại dịch vụ Song Khê – Nội Hoàng, tỉnh Bắc Giang; Quyền sử dụng đất và tài sản gắn liền với đất của Dự án đầu tư xây dựng nhà ở hỗn hợp và khu thương mại dịch vụ Song Khê – Nội Hoàng, tỉnh Bắc Giang; Quyền tài sản phát sinh từ Hợp đồng mua bán, cho thuê dài hạn tại Dự án đầu tư xây dựng nhà ở hỗn hợp và khu thương mại dịch vụ Song Khê – Nội Hoàng, tỉnh Bắc Giang (Quyền phải thu).', '03/2026'),
